class Node:
    def __init__(self, val, next=None):
        self.val = val
        self.next = next

def reverse_list(vals):
    head = None
    for v in reversed(vals):
        head = Node(v, head)

    prev, curr = None, head
    while curr:
        next_ = curr.next
        curr.next = prev
        prev = curr
        curr = next_

    out = []
    node = prev
    while node:
        out.append(node.val)
        node = node.next
    return out
